import{_ as l,o as i,c as e,a3 as o}from"./chunks/framework.gsMzR_Kb.js";const p=JSON.parse('{"title":"学习计划","description":"一份兼顾阅读、整理、写作与站点沉淀的长期计划。","frontmatter":{"title":"学习计划","description":"一份兼顾阅读、整理、写作与站点沉淀的长期计划。"},"headers":[],"relativePath":"roadmap/study-plan.md","filePath":"roadmap/study-plan.md","lastUpdated":1777132262000}'),t={name:"roadmap/study-plan.md"};function r(d,a,h,n,u,c){return i(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="学习计划" tabindex="-1">学习计划 <a class="header-anchor" href="#学习计划" aria-label="Permalink to &quot;学习计划&quot;">​</a></h1><p>这份计划不是“学完再写”，而是：</p><blockquote><p>一边学，一边整理，一边把结构长出来。</p></blockquote><h2 id="总原则" tabindex="-1">总原则 <a class="header-anchor" href="#总原则" aria-label="Permalink to &quot;总原则&quot;">​</a></h2><ul><li>读原典，但不过度追求一次读懂</li><li>学一段，整理一段，输出一段</li><li>原典阅读与站点沉淀并行，不互相等待</li><li>以小模块推进，避免拖成“大工程”</li></ul><h2 id="四条并行线" tabindex="-1">四条并行线 <a class="header-anchor" href="#四条并行线" aria-label="Permalink to &quot;四条并行线&quot;">​</a></h2><h3 id="_1-原典阅读线" tabindex="-1">1. 原典阅读线 <a class="header-anchor" href="#_1-原典阅读线" aria-label="Permalink to &quot;1. 原典阅读线&quot;">​</a></h3><p>当前可保持两条主线：</p><ul><li><code>易经线</code>：按卦序持续学习</li><li><code>道家线</code>：以《道德经》→《庄子》→《列子》为主干</li></ul><h3 id="_2-结构整理线" tabindex="-1">2. 结构整理线 <a class="header-anchor" href="#_2-结构整理线" aria-label="Permalink to &quot;2. 结构整理线&quot;">​</a></h3><p>每次学习后至少沉淀一种内容：</p><ul><li>一条术语卡</li><li>一篇导读卡</li><li>一份阅读索引</li><li>一则三问笔记</li></ul><h3 id="_3-站点建设线" tabindex="-1">3. 站点建设线 <a class="header-anchor" href="#_3-站点建设线" aria-label="Permalink to &quot;3. 站点建设线&quot;">​</a></h3><p>每周至少完成一个“对外可读”的小节点：</p><ul><li>一个入口页</li><li>一个原典导读页</li><li>一个专题页</li><li>一个阶段性笔记页</li></ul><h3 id="_4-个人理论观察线" tabindex="-1">4. 个人理论观察线 <a class="header-anchor" href="#_4-个人理论观察线" aria-label="Permalink to &quot;4. 个人理论观察线&quot;">​</a></h3><p>暂不急着系统发布 <code>Dao</code> 核心理论，但可以持续记录：</p><ul><li>哪些概念与现代学习有关</li><li>哪些地方与 <code>Dao-is-Edu</code> 产生共鸣</li><li>哪些理解值得后续抽象成方法论</li></ul><h2 id="节奏建议" tabindex="-1">节奏建议 <a class="header-anchor" href="#节奏建议" aria-label="Permalink to &quot;节奏建议&quot;">​</a></h2><h3 id="日节奏" tabindex="-1">日节奏 <a class="header-anchor" href="#日节奏" aria-label="Permalink to &quot;日节奏&quot;">​</a></h3><ul><li>读：20-40 分钟</li><li>记：10-20 分钟</li><li>整：10-20 分钟</li></ul><h3 id="周节奏" tabindex="-1">周节奏 <a class="header-anchor" href="#周节奏" aria-label="Permalink to &quot;周节奏&quot;">​</a></h3><ul><li>完成 1 个原典阅读节点</li><li>完成 1-2 个小文档沉淀</li><li>回顾 1 次已有结构是否需要调整</li></ul><h3 id="月节奏" tabindex="-1">月节奏 <a class="header-anchor" href="#月节奏" aria-label="Permalink to &quot;月节奏&quot;">​</a></h3><ul><li>形成 1 个专题小结</li><li>修订 1 次阅读地图</li><li>判断哪些内容值得上首页或进入专题</li></ul><h2 id="当前最适合先做的内容" tabindex="-1">当前最适合先做的内容 <a class="header-anchor" href="#当前最适合先做的内容" aria-label="Permalink to &quot;当前最适合先做的内容&quot;">​</a></h2><ol><li><code>道德经</code> 导读</li><li><code>易经</code> 学习方法页</li><li>六十四卦目录与记录模板</li><li>阴阳 / 无为 / 变易 三个基础专题</li></ol><h2 id="你现在的优势" tabindex="-1">你现在的优势 <a class="header-anchor" href="#你现在的优势" aria-label="Permalink to &quot;你现在的优势&quot;">​</a></h2><ul><li>正在真实学习，不是空想搭站</li><li>有持续输出的意愿</li><li>可以借助 AI 降低整理门槛，把精力放回内容判断</li></ul><p>这意味着：</p><blockquote><p>现在最重要的不是“做完”，而是建立可持续迭代的最小系统。</p></blockquote>',31)])])}const b=l(t,[["render",r]]);export{p as __pageData,b as default};
